import axios from "axios"
const url = "http://localhost:8080/api/categoryApi";

//„Ч„Щ„§„Х„© „Ы„Ь „Ф„І„Ш„Т„Х„®„Щ„Х„™
export const getAll = async() => {
    try {
        const {data}=await axios.get(`${url}/getAllCategories`)
        return data;
    }
    catch(e) {
        console.log(e)
    }
}
//„Ч„Щ„§„Х„© „І„Ш„Т„Х„®„Щ„Ф „Ь„§„Щ „І„Х„У
export const getById = async(id) => {
        try {
        const {data}=await axios.get(`${url}/getCategoryById/${id}`)
        return data;
    }
    catch(e) {
        console.log(e)
    }
}
//„Ю„Ч„Щ„І„™ „І„Ш„Т„Х„®„Щ„Ф „Ь„§„Щ „І„Х„У
export const deleteCategory = async(id) => {
        try {
            const {data} = await axios.delete(`${url}/deleteCategory/${id}`)
            return data;
        }
        catch(e) {
            console.log(e)
        }
}

//„Ф„Х„°„§„™ „І„Ш„Т„Х„®„Щ„Ф
export const addCategory = async(category) => {
    try {
        const {data}=await axios.post(`${url}/postCategory`,category)
        return data;
    }
    catch(e) {
        console.log(e)
    }
}

//„Ґ„У„Ы„Х„Я „І„Ш„Т„Х„®„Щ„Ф „Ь„§„Щ „І„Х„У
export const updateCategory = async(id,category) => {
    try {
        const {data}=await axios.put(`${url}/updateCategory/${id}`,category)
        return data;
    }
    catch(e) {
        console.log(e)
    }
}
